$path="C:\Users\Scott-Pc\clawd\wtd-package-engine\db\schema.sql";
$text=Get-Content $path -Raw;
$start=$text.IndexOf("create table if not exists supplier_product_map");
if($start -lt 0){throw "supplier_product_map block not found"}
# find end of index statement line after it
$idxEnd=$text.IndexOf("create index if not exists supplier_product_map_internal_idx", $start);
if($idxEnd -lt 0){throw "index stmt not found"}
$idxEndLine=$text.IndexOf(";", $idxEnd);
$idxEndLine=$idxEndLine+1;
$block=$text.Substring($start, $idxEndLine-$start);
# remove block
$text2=$text.Remove($start, $idxEndLine-$start);
# find insertion point: end of product table (first occurrence)
$prodStart=$text2.IndexOf("create table if not exists product (");
if($prodStart -lt 0){throw "product table not found"}
$prodEnd=$text2.IndexOf(");", $prodStart);
if($prodEnd -lt 0){throw "product end not found"}
$prodEnd=$prodEnd+2;
# insert block after product table
$text3=$text2.Insert($prodEnd, "\r\n\r\n"+$block+"\r\n");
Set-Content -Path $path -Value $text3 -Encoding UTF8;
"Reordered supplier_product_map after product in schema.sql"

