const axios = require('axios');

class WheelProsAuthClient {
  constructor({ authBaseUrl, userName, password, tokenSkewMs = 60_000 }) {
    this.authBaseUrl = authBaseUrl;
    this.userName = userName;
    this.password = password;
    this.tokenSkewMs = tokenSkewMs;

    this._token = null;
    this._expiresAtMs = 0;
    this._refreshPromise = null;

    this.http = axios.create({
      baseURL: authBaseUrl,
      timeout: 20_000,
      headers: { Accept: 'application/json', 'Content-Type': 'application/json' }
    });
  }

  hasValidToken() {
    return !!this._token && Date.now() < (this._expiresAtMs - this.tokenSkewMs);
  }

  async refreshToken() {
    if (this._refreshPromise) return this._refreshPromise;

    this._refreshPromise = (async () => {
      if (!this.userName || !this.password) {
        throw new Error('WheelPros credentials missing (WHEELPROS_USERNAME/WHEELPROS_PASSWORD)');
      }

      const res = await this.http.post('v1/login', {
        userName: this.userName,
        password: this.password
      });

      const data = res.data || {};
      if (!data.accessToken) {
        const err = new Error('WheelPros auth did not return accessToken');
        err.details = data;
        throw err;
      }

      const expiresInSec = Number(data.expiresIn ?? 3600);
      this._token = data.accessToken;
      this._expiresAtMs = Date.now() + expiresInSec * 1000;

      return {
        accessToken: this._token,
        expiresIn: expiresInSec,
        tokenType: data.tokenType ?? 'Bearer'
      };
    })();

    try {
      return await this._refreshPromise;
    } finally {
      this._refreshPromise = null;
    }
  }

  async getToken() {
    if (this.hasValidToken()) return this._token;
    await this.refreshToken();
    return this._token;
  }
}

class WheelProsProductsClient {
  constructor({ productsBaseUrl, authClient }) {
    this.authClient = authClient;
    this.http = axios.create({
      baseURL: productsBaseUrl,
      timeout: 30_000,
      headers: { Accept: 'application/json' }
    });
  }

  async request(config) {
    let token = await this.authClient.getToken();

    const attempt = async (bearerToken) => {
      return this.http.request({
        ...config,
        headers: {
          ...(config.headers || {}),
          Authorization: `Bearer ${bearerToken}`
        }
      });
    };

    try {
      return await attempt(token);
    } catch (e) {
      const status = e?.response?.status;
      if (status === 401 || status === 403) {
        const refreshed = await this.authClient.refreshToken();
        token = refreshed.accessToken;
        return await attempt(token);
      }
      throw e;
    }
  }
}

module.exports = { WheelProsAuthClient, WheelProsProductsClient };

const { WheelProsAuthClient, WheelProsProductsClient } = require('./wheelprosClient');

/**
 * WheelProsAdapter implements WheelSupplierAdapter.
 * Normalizes Wheel Pros Product API responses.
 */
class WheelProsAdapter {
  constructor({ authBaseUrl, productsBaseUrl, userName, password, company, currencyCode }) {
    this.code = 'WHEELPROS';
    this.company = company;
    this.currencyCode = currencyCode;

    this.auth = new WheelProsAuthClient({ authBaseUrl, userName, password });
    this.products = new WheelProsProductsClient({ productsBaseUrl, authClient: this.auth });
  }

  getCapabilities() {
    return { code: this.code, mode: 'api', supportsRealtimeInventory: true };
  }

  /**
   * @param {object} query
   */
  async searchWheels(query = {}) {
    const params = {
      page: Number(query.page || 1),
      pageSize: Number(query.pageSize || 20),
      fields: query.fields || 'inventory,price',
      priceType: query.priceType || 'msrp',
      company: query.company || this.company,
      currencyCode: query.currencyCode || this.currencyCode,
      availabilityType: query.availabilityType || 'AVAILABLE',
      realTimeInventory:
        query.realTimeInventory !== undefined ? query.realTimeInventory : false,
      ...query
    };

    const res = await this.products.request({
      method: 'GET',
      url: 'v1/search/wheel',
      params
    });

    return res.data;
  }

  async getWheelDetails(externalSku) {
    const res = await this.products.request({
      method: 'GET',
      url: `v1/details/${encodeURIComponent(externalSku)}`
    });

    return res.data;
  }

  /**
   * Normalize a Wheel Pros wheel record (from search or details) into a spec row.
   * @param {any} rec
   */
  toWheelSpec(rec) {
    const p = rec?.properties || {};
    const inv = rec?.inventory || {};

    const tpms = p.tpmsCompatible;
    const tpmsBool = tpms == null ? null : Number(tpms) === 1;

    const load = p.loadRating;
    const loadLbs =
      typeof load === 'string'
        ? parseMaybeNumber(load.split('/')[0])
        : parseMaybeNumber(load);

    return {
      diameterIn: parseMaybeNumber(p.diameter),
      widthIn: parseMaybeNumber(p.width),
      offsetMm: parseMaybeNumber(p.offset),
      boltPattern: p.boltPattern || null,
      centerBoreMm: parseMaybeNumber(p.centerbore || p.centerBore || p.center_bore_mm),
      finish: p.finish || null,
      finishCode: p.finishCode || null,
      model: p.model || rec?.model || null,
      tpmsCompatible: tpmsBool,
      loadRatingLbs: loadLbs,
      inventoryType: inv.type || null
    };
  }

  /**
   * Normalize inventory snapshot.
   */
  toInventory(rec) {
    const inv = rec?.inventory || {};
    return {
      localStock: inv.localStock ?? null,
      globalStock: inv.globalStock ?? null,
      inventoryType: inv.type ?? null
    };
  }

  /**
   * Normalize pricing snapshot. Returns a flat array of {priceType, amount, currency}.
   */
  toPrices(rec) {
    const prices = rec?.prices || {};
    const out = [];

    for (const [priceType, arr] of Object.entries(prices)) {
      if (!Array.isArray(arr)) continue;

      for (const p of arr) {
        const amount = parseMaybeNumber(p.currencyAmount);
        const currency = p.currencyCode || this.currencyCode;
        if (amount != null) out.push({ priceType, amount, currency });
      }
    }

    return out;
  }
}

function parseMaybeNumber(v) {
  if (v == null) return null;
  if (typeof v === 'number' && Number.isFinite(v)) return v;
  const n = Number(String(v).trim());
  return Number.isFinite(n) ? n : null;
}

module.exports = { WheelProsAdapter };

const { z } = require('zod');

const envSchema = z.object({
  PORT: z.coerce.number().default(8790),
  DATABASE_URL: z.string().min(1),

  API_KEY: z.string().optional(),

  WHEELPROS_AUTH_BASE_URL: z.string().default('https://api.wheelpros.com/auth'),
  WHEELPROS_PRODUCTS_BASE_URL: z.string().default('https://api.wheelpros.com/products'),
  WHEELPROS_USERNAME: z.string().optional(),
  WHEELPROS_PASSWORD: z.string().optional(),
  WHEELPROS_COMPANY: z.coerce.number().default(1500),
  WHEELPROS_CURRENCY: z.string().default('USD'),

  // Wheel-Size (fitment)
  WHEEL_SIZE_BASE_URL: z.string().optional(),
  WHEEL_SIZE_API_KEY: z.string().optional(),

  // Backward-compatible aliases
  WHEELSIZE_BASE_URL: z.string().optional(),
  WHEELSIZE_API_KEY: z.string().optional(),

  // Fitment caching
  FITMENT_CACHE_TTL_DAYS: z.coerce.number().default(7),

  // TireConnect scrape adapter (interim)
  TIRECONNECT_WIDGET_ID: z.string().optional(),
  TIRECONNECT_LOCATION_ID: z.string().optional(),
  TIRECONNECT_BASE_URL: z.string().optional()
});

function loadConfig(processEnv = process.env) {
  const parsed = envSchema.safeParse(processEnv);
  if (!parsed.success) {
    const err = new Error('Invalid environment configuration');
    err.details = parsed.error.flatten();
    throw err;
  }
  const cfg = { ...parsed.data };
  if (!cfg.WHEEL_SIZE_BASE_URL && cfg.WHEELSIZE_BASE_URL) cfg.WHEEL_SIZE_BASE_URL = cfg.WHEELSIZE_BASE_URL;
  if (!cfg.WHEEL_SIZE_API_KEY && cfg.WHEELSIZE_API_KEY) cfg.WHEEL_SIZE_API_KEY = cfg.WHEELSIZE_API_KEY;
  return cfg;
}

module.exports = { loadConfig };

