const express = require('express');
const { z } = require('zod');

const RecommendSchema = z.object({
  vehicleId: z.string().uuid(),
  preferences: z.record(z.any()).optional()
});

function packagesRouter({ packageEngineService }) {
  const r = express.Router();

  r.post('/recommend', express.json({ limit: '1mb' }), async (req, res, next) => {
    try {
      const parsed = RecommendSchema.safeParse(req.body);
      if (!parsed.success) {
        return res.status(400).json({ error: 'validation_failed', details: parsed.error.flatten() });
      }

      const out = await packageEngineService.recommend(parsed.data);
      res.json(out);
    } catch (e) {
      next(e);
    }
  });

  return r;
}

module.exports = { packagesRouter };

class PackageEngineService {
  /**
   * @param {{vehicleService:any, fitmentService:any, wheelService:any, tireService:any, tireSizeService:any}} deps
   */
  constructor({ vehicleService, fitmentService, wheelService, tireService, tireSizeService }) {
    this.vehicleService = vehicleService;
    this.fitmentService = fitmentService;
    this.wheelService = wheelService;
    this.tireService = tireService;
    this.tireSizeService = tireSizeService;
  }

  /**
   * Generate package recommendations.
   * MVP: uses wheel search + fitment constraints; tire integration can be added later.
   */
  async recommend({ vehicleId, preferences }) {
    const vehicle = await this.vehicleService.getVehicleById(vehicleId);
    if (!vehicle) {
      const err = new Error('vehicle_not_found');
      err.status = 404;
      throw err;
    }

    const fitment = await this.fitmentService.getFitmentForVehicle(vehicle);

    // Tire-size comparison settings
    const plusSize = {
      warnPercent: 3.0, // warn if overall diameter differs by > 3.0%
      maxPercent: 5.0   // hard fail threshold
    };

    const baseTireSize =
      preferences?.tireSize ||
      preferences?.size ||
      fitment?.fitment?.oemTireSizes?.[0] ||
      null;

    // Wheel query derived from preferences + fitment
    const wheelQuery = {
      page: 1,
      pageSize: 20,
      fields: 'inventory,price',
      priceType: 'msrp',
      availabilityType: 'AVAILABLE',
      realTimeInventory: false
    };

    if (preferences?.wheelDiameter) wheelQuery.diameter = Number(preferences.wheelDiameter);
    if (preferences?.boltPattern) wheelQuery.boltPattern = preferences.boltPattern;
    if (!wheelQuery.boltPattern && fitment?.fitment?.boltPattern) wheelQuery.boltPattern = fitment.fitment.boltPattern;

    if (preferences?.brand) wheelQuery.brand = preferences.brand;
    if (preferences?.finish) wheelQuery.finish = preferences.finish;
    if (preferences?.minOffset != null) wheelQuery.minOffset = Number(preferences.minOffset);
    if (preferences?.maxOffset != null) wheelQuery.maxOffset = Number(preferences.maxOffset);

    const wheelResults = await this.wheelService.searchWheels(wheelQuery);

    // Tire query: use base size if known, otherwise try wheel diameter preference/fitment.
    const inferredWheelDia = preferences?.wheelDiameter || null;
    const tireQuery = {
      vehicleId,
      size: baseTireSize,
      wheelDiameter: inferredWheelDia
    };
    const tireResults = await this.tireService.searchTires(tireQuery);

    const tires = (tireResults.results || []).slice(0, 10);

    const recs = (wheelResults.results || []).slice(0, 10).map((w, idx) => {
      const t = tires[idx % Math.max(tires.length, 1)] || null;

      const warnings = [];
      let ok = true;

      if (!baseTireSize) warnings.push('No base/OEM tire size available; plus-size comparison skipped');
      if (!t) warnings.push('No tire results available');

      // Compare tire overall diameter to base size
      if (baseTireSize && t?.properties?.size) {
        const cmp = this.tireSizeService.compareByDiameter(baseTireSize, t.properties.size);
        if (cmp) {
          const pct = Math.abs(cmp.percentDifference);
          if (pct > plusSize.warnPercent) {
            warnings.push(`plus-size warning: ${baseTireSize} → ${t.properties.size} overall diameter Δ ${cmp.percentDifference}% (${cmp.deltaOverallDiameterIn}in)`);
          }
          if (pct > plusSize.maxPercent) {
            ok = false;
            warnings.push(`plus-size FAIL: diameter difference ${pct}% exceeds ${plusSize.maxPercent}% threshold`);
          }
        } else {
          warnings.push(`Unable to parse/compare tire sizes: base=${baseTireSize}, candidate=${t?.properties?.size}`);
        }
      }

      return {
        score: 1 - (idx * 0.02),
        ranking: {
          margin: null,
          stockConfidence: null,
          shippingSpeedScore: null,
          supplierPriority: 10
        },
        wheel: w,
        tire: t,
        pricing: {
          currency: preferences?.currencyCode || 'USD'
        },
        availability: {
          wheelMaxQty: w?.inventory?.globalStock ?? null,
          tireMaxQty: t?.inventory?.globalStock ?? null,
          okForMinQuantity: true
        },
        fitment: {
          ok,
          warnings
        }
      };
    });

    return {
      vehicleId,
      fitment,
      baseTireSize,
      plusSize,
      recommendations: recs
    };
  }
}

module.exports = { PackageEngineService };

const { randomUUID } = require('crypto');

class TireSizeService {
  /**
   * Parse a tire size like "225/60R18".
   * Accepts common variants (case-insensitive, optional spaces).
   */
  parseSize(sizeStr) {
    if (!sizeStr) return null;
    const s = String(sizeStr).trim().toUpperCase().replace(/\s+/g, '');

    // 225/60R18
    const m = s.match(/^(\d{3})\/(\d{2,3})R(\d{2}(?:\.\d)?)$/);
    if (!m) return null;

    const widthMm = parseInt(m[1], 10);
    const aspectRatio = parseInt(m[2], 10);
    const wheelDiameterIn = parseFloat(m[3]);

    if (!Number.isFinite(widthMm) || !Number.isFinite(aspectRatio) || !Number.isFinite(wheelDiameterIn)) return null;

    return { size: `${widthMm}/${aspectRatio}R${wheelDiameterIn % 1 === 0 ? String(wheelDiameterIn.toFixed(0)) : String(wheelDiameterIn)}`,
      widthMm,
      aspectRatio,
      wheelDiameterIn
    };
  }

  /**
   * Compute tire geometry for comparisons.
   */
  computeGeometry(parsed) {
    if (!parsed) return null;
    const { widthMm, aspectRatio, wheelDiameterIn } = parsed;

    const widthIn = widthMm / 25.4;
    const sidewallIn = (widthMm * (aspectRatio / 100)) / 25.4;
    const overallDiameterIn = wheelDiameterIn + (2 * sidewallIn);
    const circumferenceIn = Math.PI * overallDiameterIn;
    const revsPerMile = 63360 / circumferenceIn;

    return {
      sectionWidthIn: round(widthIn, 3),
      overallDiameterIn: round(overallDiameterIn, 3),
      circumferenceIn: round(circumferenceIn, 3),
      revsPerMile: round(revsPerMile, 2)
    };
  }

  /**
   * Compare two tire sizes by overall diameter.
   * Returns signed delta and percent difference.
   */
  compareByDiameter(sizeA, sizeB) {
    const a = this.parseSize(sizeA);
    const b = this.parseSize(sizeB);
    if (!a || !b) return null;

    const ga = this.computeGeometry(a);
    const gb = this.computeGeometry(b);

    const deltaIn = gb.overallDiameterIn - ga.overallDiameterIn;
    const pct = (deltaIn / ga.overallDiameterIn) * 100;

    return {
      a: { ...a, ...ga },
      b: { ...b, ...gb },
      deltaOverallDiameterIn: round(deltaIn, 3),
      percentDifference: round(pct, 3)
    };
  }

  /**
   * Upsert tire_size row and return its id.
   * @param {import('pg').Pool} db
   */
  async upsertTireSize(db, sizeStr) {
    const parsed = this.parseSize(sizeStr);
    if (!parsed) return null;
    const geom = this.computeGeometry(parsed);

    // Try to find existing
    const found = await db.query({
      text: `select id from tire_size where size = $1`,
      values: [parsed.size]
    });
    if (found.rows[0]) return found.rows[0].id;

    const id = randomUUID();
    await db.query({
      text: `
        insert into tire_size (
          id, size, width_mm, aspect_ratio, wheel_diameter_in,
          overall_diameter_in, section_width_in, circumference_in, revs_per_mile
        ) values (
          $1::uuid, $2, $3, $4, $5,
          $6, $7, $8, $9
        )
      `,
      values: [
        id,
        parsed.size,
        parsed.widthMm,
        parsed.aspectRatio,
        parsed.wheelDiameterIn,
        geom.overallDiameterIn,
        geom.sectionWidthIn,
        geom.circumferenceIn,
        geom.revsPerMile
      ]
    });

    return id;
  }
}

function round(n, digits) {
  const p = Math.pow(10, digits);
  return Math.round(n * p) / p;
}

module.exports = { TireSizeService };

